const s3 = require('./data/s3_ai_judgments.json');
const s2 = require('./data/s2_ai_input.json');

// Create lookup from s2
const s2Map = {};
s2.forEach(c => { s2Map[c.cid] = c; });

const now = s3.filter(c => c.priority === 'now');
const soon = s3.filter(c => c.priority === 'soon');

// Sort by lastCustomerMsgDays (silence) descending
const sortFn = (a, b) => {
  const da = s2Map[a.cid]?.lastCustomerMsgDays || 999;
  const db = s2Map[b.cid]?.lastCustomerMsgDays || 999;
  return db - da;
};

now.sort(sortFn);
soon.sort(sortFn);

// Print now and soon lists
console.log('=== NOW (' + now.length + ' people) ===');
now.forEach(c => {
  const s = s2Map[c.cid];
  console.log([c.name, c.country, c.grade, c.stage, s?.lastCustomerMsgDays + 'd', c.actionHint].join(' | '));
});

console.log();
console.log('=== SOON (' + soon.length + ' people) ===');
soon.forEach(c => {
  const s = s2Map[c.cid];
  console.log([c.name, c.country, c.grade, c.stage, s?.lastCustomerMsgDays + 'd', c.actionHint].join(' | '));
});

// Also check new customers (compare with tm_conversations_full.json if exists)
